arguments.file_text:
@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="board-add-task-form">
        <div class="form-field">
            <label>Title</label>
            <input type="text" @bind="Title" placeholder="Task title" />
        </div>
        <div class="form-field">
            <label>Assignee</label>
            <input type="text" @bind="Assignee" placeholder="Assignee name" />
        </div>
        <div class="form-field">
            <label>Priority</label>
            <select @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="form-field">
            <label>Due Date</label>
            <input type="date" @bind="DueDate" />
        </div>
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@IsSaving">Save</button>
            <button class="btn-cancel" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = string.Empty;
    private string Assignee = string.Empty;
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title))
            return;

        IsSaving = true;
        await OnTaskCreated.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;
        ResetForm();
        IsVisible = false;
    }

    private void ResetForm()
    {
        Title = string.Empty;
        Assignee = string.Empty;
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
    }
}

@page "/board"
@using sv_5c06d857a62042269b6fe2d2ac99db4b.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" SearchTextChanged="OnSearchTextChanged" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRightClicked="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="args => CreateTask(args, "To Do")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeftClicked="task => MoveTask(task, "To Do")"
                     OnMoveRightClicked="task => MoveTask(task, "Done")"
                     OnTaskCreated="args => CreateTask(args, "In Progress")" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeftClicked="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="args => CreateTask(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private void OnSearchTextChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) args,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // CreateTaskAsync returns the task; its status may differ from the column, so we normalize
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

