        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeftClicked { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRightClicked { get; set; }

    private bool IsMoving;

    private async System.Threading.Tasks.Task OnMoveLeft()
    {
        IsMoving = true;
        await OnMoveLeftClicked.InvokeAsync(Task);
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRight()
    {
        IsMoving = true;
        await OnMoveRightClicked.InvokeAsync(Task);
        IsMoving = false;
    }
}
"}

